import{_ as t,c as n,o as i,ae as a}from"./chunks/framework.CeIuOzFV.js";const h=JSON.parse('{"title":"Widgets","description":"","frontmatter":{},"headers":[],"relativePath":"de/user-manual/content-management/widgets.md","filePath":"de/user-manual/content-management/widgets.md"}'),r={name:"de/user-manual/content-management/widgets.md"};function d(l,e,s,o,u,g){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="widgets" tabindex="-1">Widgets <a class="header-anchor" href="#widgets" aria-label="Permalink to &quot;Widgets&quot;">​</a></h1><h2 id="verfugbare-widgets" tabindex="-1">Verfügbare Widgets <a class="header-anchor" href="#verfugbare-widgets" aria-label="Permalink to &quot;Verfügbare Widgets&quot;">​</a></h2><p>Die folgenden Widgets können derzeit verwendet werden, um Seiten zu gestalten:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Widget</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;">Avatar</td><td style="text-align:left;">Ein zentrales, rundes Bild mit optionalem Untertext.</td></tr><tr><td style="text-align:left;">Buttons</td><td style="text-align:left;">Eine Liste von Buttons, die neue Seiten öffnen. Jeder Button kann individuell gestaltet werden.</td></tr><tr><td style="text-align:left;">Bildergalerie</td><td style="text-align:left;">Ein Widget, das ein oder mehrere Bilder sowie optionalen Text enthält. Die Position von Bild(en) und Text kann konfiguriert werden.</td></tr><tr><td style="text-align:left;">Info-Box</td><td style="text-align:left;">Eine Info-Box mit Überschrift und Textinhalt. Kann in den Farben Grün, Rot und Gelb dargestellt werden.</td></tr><tr><td style="text-align:left;">Objektsuche</td><td style="text-align:left;">Ein Widget, das Eingaben für eine Objektsuche bereitstellt. Wenn ein Suchbegriff konfiguriert ist, wird das Suchergebnis direkt angezeigt.</td></tr><tr><td style="text-align:left;">Seitentitel</td><td style="text-align:left;">Ein Seitentitel mit optionalem Bild über das Browserfenster und einem fettgedruckten, zentralen Titeltext.</td></tr><tr><td style="text-align:left;">Text</td><td style="text-align:left;">Eine Überschrift mit Textinhalt. Markdown wird unterstützt, um den Text weiter zu strukturieren und zu formatieren.</td></tr></tbody></table><h2 id="audio-inhalte" tabindex="-1">Audio-Inhalte <a class="header-anchor" href="#audio-inhalte" aria-label="Permalink to &quot;Audio-Inhalte&quot;">​</a></h2><p>Widgets mit Textinhalten können Audiodateien aus ihrem Text mittels KI-gestützter Text-to-Speech (TTS) generieren lassen. Die erzeugten Audiodateien können z.B. in Content-Exporten verwendet werden, um ein Audio-Erlebnis der Sammlung zu bieten.</p><p>Um diese Funktion zu nutzen, muss die KI in der <a href="./../settings/ai.html">KI-Konfiguration</a> aktiviert und konfiguriert sein.</p>',7)])])}const m=t(r,[["render",d]]);export{h as __pageData,m as default};
